import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;
import java.io.*;
import java.util.*;

public class XSSFixedCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        String sanitizedInput = ESAPI.encoder().encodeForHTML(userInput); // Sanitize user input

        System.out.println("Hello, " + sanitizedInput + "!"); // Display sanitized input

        // Other vulnerable code that can lead to XSS
        try {
            String encodedScript = ESAPI.encoder().encodeForJavaScript("<script>alert('XSS Vulnerability')</script>"); // Encode script
            System.out.println(encodedScript);
        } catch (EncodingException e) {
            System.err.println("Error encoding script: " + e.getMessage());
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
